import { whiteLabel } from "shared/WhiteLabel";
import { procedure, router } from "../trpc";
import { z } from "zod";
import Role, {
  allRoles,
  isPermitted,
  roleProfile,
  zRoles,
} from "../../shared/Role";
import db from "../database/db";
import { Op, Transaction } from "sequelize";
import { authUser } from "../auth";
import User, {
  UserWithMergeInfo,
  isAcceptedMentee,
  zMinUser,
  zUser,
  zUserWithMergeInfo,
} from "../../shared/User";
import { UserFilter, zUserFilter } from "../../shared/UserFilter";
import {
  defaultMentorCapacity,
  zMentorPreference,
  zUserPreference,
} from "../../shared/UserPreference";
import { compareChinese } from "../../shared/strings/compareChinese";
import { isValidChineseName } from "../../shared/strings/isValidChineseName";
import {
  generalBadRequestError,
  noPermissionError,
  notFoundError,
} from "../errors";
import { zInterviewType } from "../../shared/InterviewType";
import {
  minUserAttributes,
  userAttributes,
  userInclude,
} from "../database/models/attributesAndIncludes";
import { getCalibrationAndCheckPermissionSafe } from "./calibrations";
import sequelize from "../database/sequelize";
import { zMenteeStatus } from "../../shared/MenteeStatus";
import { zMinUserAndProfile, zUserProfile } from "../../shared/UserProfile";
import { zDateColumn } from "../../shared/DateColumn";
import {
  getUser2MentorshipCount,
  whereMentorshipIsOngoing,
} from "./mentorships";
import { UserState, zUserState } from "../../shared/UserState";
import { invalidateUserCache } from "../../pages/api/auth/[...nextauth]";
import { zTraitsPreference } from "../../shared/Traits";
import invariant from "../../shared/invariant";
import { checkAndComputeUserFields } from "./checkAndComputeUserFields";
import { encodeXField } from "../jinshuju";

// Import self module to allow Sinon stubbing of exported functions in tests
import * as selfModule from "./users";

const create = procedure
  .use(authUser("UserAdmin"))
  .input(
    z.object({
      name: z.string(),
      phone: z.string().nullable(),
      email: z.string().nullable(),
      wechatUnionId: z.string().nullable(),
      roles: zRoles,
    }),
  )
  .mutation(async ({ input: { name, phone, email, wechatUnionId, roles } }) => {
    if (!phone) {
      throw generalBadRequestError("手机号是必填的。");
    }

    await sequelize.transaction(async (transaction) => {
      await db.User.create(
        {
          roles,
          phone,
          wechatUnionId,
          ...(await checkAndComputeUserFields({
            email,
            name,
            isVolunteer: isPermitted(roles, "Volunteer"),
            oldUrl: null,
            transaction,
          })),
        },
        { transaction },
      );
    });
  });

/**
 * Returned users are ordered by Pinyin.
 */
const list = procedure
  .use(
    authUser([
      "UserAdmin",
      "GroupAdmin",
      "MentorshipAdmin",
      "MentorshipOperator",
    ]),
  )
  .input(zUserFilter)
  .output(
    z.object({
      items: z.array(zUserWithMergeInfo),
      nextCursor: z.number().nullish(),
    }),
  )
  .query(async ({ ctx: { me }, input: filter }) => {
    return await listImpl(me, filter);
  });

export async function listImpl(
  me: User,
  filter: UserFilter,
  transaction?: Transaction,
): Promise<{
  items: UserWithMergeInfo[];
  nextCursor: number | null | undefined;
}> {
  if (
    (filter.includeMerged === true || filter.returnMergeInfo === true) &&
    !isPermitted(me.roles, "UserAdmin")
  ) {
    throw noPermissionError(
      "数据",
      "`includeMerged` or `returnMergeInfo` user filter",
    );
  }

  // Force type checking.
  const volunteer: Role = "Volunteer";
  const mentor: Role = "Mentor";

  const limit = filter.limit;

  let menteeIdsFromMentorSearch: string[] | undefined;
  if (filter.includeMentorSearch === true && filter.matchesNameOrEmail) {
    const mentorships = await db.Mentorship.findAll({
      attributes: ["menteeId"],
      where: {
        ...whereMentorshipIsOngoing,
        transactional: false,
      },
      include: [
        {
          association: "mentor",
          attributes: [],
          where: {
            [Op.or]: [
              { name: { [Op.iLike]: `%${filter.matchesNameOrEmail}%` } },
              { pinyin: { [Op.iLike]: `%${filter.matchesNameOrEmail}%` } },
            ],
          },
        },
      ],
      transaction,
    });
    menteeIdsFromMentorSearch = mentorships.map((m) => m.menteeId);
  }

  const items = await db.User.findAll({
    transaction,
    ...(limit !== undefined && limit !== null ? { limit: limit + 1 } : {}),
    offset: filter.cursor ?? 0,
    order: [["pinyin", "ASC"]],

    attributes: [
      ...userAttributes,
      ...(filter.returnMergeInfo === true ? ["wechatUnionId"] : []),
    ],

    include: [
      ...userInclude,
      ...(filter.returnMergeInfo === true
        ? [
            {
              association: "mergedToUser",
              attributes: minUserAttributes,
            },
          ]
        : []),
    ],

    where: {
      // Use [Op.and] to connect sub-clauses to avoid potential key conflicts
      // (like multiple [Op.or] conditions) when query options are merged.
      [Op.and]: [
        ...(filter.includeMerged === true
          ? []
          : [
              {
                mergedTo: { [Op.eq]: null },
              },
            ]),

        ...(filter.includeNonVolunteersMentors === true
          ? []
          : [
              {
                [Op.or]: [
                  { roles: { [Op.contains]: [volunteer] } },
                  { roles: { [Op.contains]: [mentor] } },
                ],
              },
            ]),

        ...(filter.containsRoles === undefined
          ? []
          : [
              {
                [Op.and]: filter.containsRoles.map((r) => ({
                  roles: { [Op.contains]: [r] },
                })),
              },
            ]),

        ...(filter.menteeStatus === undefined
          ? []
          : [
              {
                menteeStatus: filter.menteeStatus,
              },
            ]),

        ...(filter.pointOfContactId === undefined
          ? []
          : [
              {
                pointOfContactId: filter.pointOfContactId,
              },
            ]),

        ...(filter.matchesNameOrEmail === undefined
          ? []
          : [
              {
                [Op.or]: [
                  {
                    pinyin: {
                      [Op.iLike]: `%${filter.matchesNameOrEmail}%`,
                    },
                  },
                  {
                    name: {
                      [Op.iLike]: `%${filter.matchesNameOrEmail}%`,
                    },
                  },
                  {
                    email: {
                      [Op.iLike]: `%${filter.matchesNameOrEmail}%`,
                    },
                  },
                  ...(menteeIdsFromMentorSearch !== undefined
                    ? [
                        {
                          id: {
                            [Op.in]: menteeIdsFromMentorSearch,
                          },
                        },
                      ]
                    : []),
                ],
              },
            ]),

        ...(filter.ids === undefined
          ? []
          : [
              {
                id: { [Op.in]: filter.ids },
              },
            ]),
      ],
    },
  });

  let nextCursor = undefined;
  if (limit !== undefined && limit !== null && items.length > limit) {
    items.pop();
    nextCursor = (filter.cursor ?? 0) + limit;
  }

  return {
    items: items as unknown as UserWithMergeInfo[],
    nextCursor,
  };
}

const zListMentorsOutput = z.array(
  zMinUserAndProfile.merge(
    z.object({
      // relational == true if and only if the mentor's roles don't include
      // TransactionalMentor and the mentor's capacity is not exhausted.
      relational: z.boolean(),
      traitsPreference: zTraitsPreference.nullable(),
    }),
  ),
);
export type ListMentorsOutput = z.infer<typeof zListMentorsOutput>;

const listMentors = procedure
  .use(authUser())
  .output(zListMentorsOutput)
  .query(async ({ ctx: { me } }) => {
    if (
      !isAcceptedMentee(
        me.roles,
        me.menteeStatus,
        "includeTransactionalOnly",
      ) &&
      !isPermitted(me.roles, [
        "Mentor",
        "MentorshipAdmin",
        "MentorshipOperator",
      ])
    ) {
      throw noPermissionError("导师");
    }
    return await listMentorsImpl();
  });

export async function listMentorsImpl(): Promise<ListMentorsOutput> {
  // Force type check
  const mentorRole: Role = "Mentor";
  const users = await db.User.findAll({
    where: { roles: { [Op.contains]: [mentorRole] } },
    attributes: [...minUserAttributes, "roles", "preference", "profile"],
  });

  const user2mentorships = await getUser2MentorshipCount();

  return users.map((u) => {
    const transactional = u.roles.includes("TransactionalMentor");
    const cap = transactional
      ? 0
      : (u.preference?.mentor?.最多匹配学生 ?? defaultMentorCapacity) -
        (user2mentorships[u.id] ?? 0);

    return {
      user: u,
      profile: u.profile ?? {},
      relational: cap > 0,
      traitsPreference: u.preference?.mentor?.学生特质 ?? null,
    };
  });
}

const zListMentorStatsOutput = z.array(
  z.object({
    user: zUser,
    mentorships: z.number(),
    preference: zMentorPreference,
    profile: zUserProfile,
  }),
);
export type ListMentorStatsOutput = z.infer<typeof zListMentorStatsOutput>;

/**
 * Compared to listMentorsRoute, this route is restricted to MentorshipAdmin
 * access.
 */
const listMentorStats = procedure
  .use(authUser(["MentorshipAdmin", "MentorshipOperator"]))
  .output(zListMentorStatsOutput)
  .query(listMentorStatsImpl);

export async function listMentorStatsImpl(): Promise<ListMentorStatsOutput> {
  // Force type check
  const mentorRole: Role = "Mentor";
  const users = await db.User.findAll({
    where: { roles: { [Op.contains]: [mentorRole] } },
    attributes: [...userAttributes, "profile", "preference"],
    include: userInclude,
  });

  const user2mentorships = await getUser2MentorshipCount();
  const ret = users.map((u) => ({
    user: u,
    mentorships: user2mentorships[u.id] ?? 0,
    preference: u.preference?.mentor ?? {},
    profile: u.profile ?? {},
  }));

  ret.sort((a, b) => compareChinese(a.user.name, b.user.name));
  return ret;
}

const listVolunteers = procedure
  .use(authUser(["Volunteer"]))
  .output(
    z.array(
      zMinUserAndProfile.merge(
        z.object({
          likes: z.number(),
          kudos: z.number(),
          updatedAt: zDateColumn,
        }),
      ),
    ),
  )
  .query(async () => {
    // Force type check
    const volunteerRole: Role = "Volunteer";
    return (
      await db.User.findAll({
        where: { roles: { [Op.contains]: [volunteerRole] } },
        attributes: [
          ...minUserAttributes,
          "roles",
          "profile",
          "updatedAt",
          "likes",
          "kudos",
        ],
      })
    ).map((u) => ({
      user: u,
      profile: u.profile ?? {},
      updatedAt: u.updatedAt,
      likes: u.likes ?? 0,
      kudos: u.kudos ?? 0,
    }));
  });

/**
 * Given foo.bar@gmail.com, return f***@gmail.com
 */
export function redactEmail(email: string): string {
  const [name, domain] = email.split("@");
  if (!domain) return email;
  return `${name.slice(0, 1)}***@${domain}`;
}

/**
 * Only selected fields in the User object are respected. See code for details.
 */
const update = procedure
  .use(authUser())
  .input(
    zUser.merge(
      z.object({
        wechatUnionId: z.string().nullish(),
      }),
    ),
  )
  .mutation(async ({ input, ctx: { me } }) => {
    await sequelize.transaction(async (transaction) => {
      await updateImpl(me, input, transaction);
    });
  });

export async function updateImpl(
  me: User,
  input: User & { wechatUnionId?: string | null },
  transaction: Transaction,
) {
  const user = await db.User.findByPk(input.id, {
    attributes: ["id", "roles", "url", "name"],
    transaction,
  });
  if (!user) {
    throw notFoundError("用户", input.id);
  }

  const isUserAdmin = isPermitted(me.roles, "UserAdmin");
  if (!isUserAdmin) {
    // Non-UserAdmins can only update their own profile.
    if (me.id !== input.id) {
      throw noPermissionError("用户", input.id);
    }

    const rolesToAdd = input.roles.filter((r) => !user.roles.includes(r));
    const rolesToRemove = user.roles.filter((r) => !input.roles.includes(r));
    if ([...rolesToAdd, ...rolesToRemove].length) {
      throw noPermissionError("用户", input.id);
    }
  } else {
    await selfModule.updateWechatUnionId(
      me.roles,
      user.id,
      input.wechatUnionId === "" ? null : input.wechatUnionId,
      transaction,
    );
  }

  // Only check Chinese name when updating name. Allow invalid names created
  // during sign-in to be carried over. See createUser.
  if (user.name !== input.name && !isValidChineseName(input.name)) {
    throw generalBadRequestError("中文姓名无效。");
  }

  // Normalize empty strings to null for fields that should be nullable
  const email = input.email === "" ? null : input.email;
  const phone = input.phone === "" ? null : input.phone;
  const wechat = input.wechat === "" ? null : input.wechat;
  const url = input.url === "" ? null : input.url;

  // TODO: For cleaner code, separate self updates from admin updates.
  await user.update(
    {
      wechat,

      ...(await checkAndComputeUserFields({
        name: input.name,
        isVolunteer: isPermitted(input.roles, "Volunteer"),
        oldUrl: user.url,
        url,
        transaction,
      })),

      // fields that only UserAdmins can change
      ...(isUserAdmin && {
        roles: input.roles,
        email,
        phone,
      }),
    },
    { transaction },
  );

  invalidateUserCache(user.id);
}

/**
 * Remove obsolete entries from next-auth's accounts table if the wechatUnionId
 * is changed. This is needed because next-auth would overwise map the
 * wechatUnionId to the wrong row in the users table next time the user logs in.
 * Dp nothing if wechatUnionId === undefined.
 */
export async function updateWechatUnionId(
  myRoles: Role[],
  userId: string,
  wechatUnionId: string | null | undefined,
  transaction: Transaction,
) {
  invariant(isPermitted(myRoles, "UserAdmin"), `role violation`);

  if (wechatUnionId === undefined) return;

  const existing = await db.User.findByPk(userId, {
    attributes: ["id", "wechatUnionId"],
    transaction,
  });
  invariant(existing, `User not found: ${userId}`);

  if (existing.wechatUnionId === wechatUnionId) return;

  const Account = sequelize.models.account;
  invariant(Account, "Account model is not initialized");

  if (existing.wechatUnionId) {
    await Account.destroy({
      where: { providerAccountId: existing.wechatUnionId },
      transaction,
    });
  }

  if (wechatUnionId) {
    await Account.destroy({
      where: { providerAccountId: wechatUnionId },
      transaction,
    });
  }

  await existing.update(
    { wechatUnionId },
    { where: { id: userId }, transaction },
  );
}

const setUserPreference = procedure
  .use(authUser())
  .input(
    z.object({
      userId: z.string(),
      preference: zUserPreference,
    }),
  )
  .mutation(async ({ ctx: { me }, input: { userId, preference } }) => {
    if (me.id !== userId && !isPermitted(me.roles, "UserAdmin")) {
      throw noPermissionError("用户", userId);
    }

    const [cnt] = await db.User.update(
      { preference },
      {
        where: { id: userId },
      },
    );
    if (cnt == 0) throw notFoundError("用户", userId);
  });

const setMenteeStatus = procedure
  .use(authUser("MentorshipAdmin"))
  .input(
    z.object({
      userId: z.string(),
      menteeStatus: zMenteeStatus.nullable(),
    }),
  )
  .mutation(async ({ input: { userId, menteeStatus } }) => {
    const [cnt] = await db.User.update(
      { menteeStatus },
      {
        where: { id: userId },
      },
    );
    if (cnt == 0) throw notFoundError("用户", userId);
    invalidateUserCache(userId);
  });

const get = procedure
  .use(authUser())
  .input(z.string())
  .output(zMinUser)
  .query(async ({ ctx: { me }, input: userId }) => {
    return await sequelize.transaction(async (transaction) => {
      if (
        me.id !== userId &&
        !isPermitted(me.roles, "UserAdmin") &&
        !(await isPermittedtoAccessMentor(me, userId, transaction)) &&
        !(await isPermittedtoAccessMentee(
          me,
          userId,
          transaction,
          "readMetadata",
        ))
      ) {
        throw noPermissionError("用户", userId);
      }

      const u = await db.User.findByPk(userId, {
        attributes: minUserAttributes,
        transaction,
      });

      if (!u) throw notFoundError("用户", userId);
      return u;
    });
  });

/**
 * TODO: Remove this route. Use routes that returns more specific data instead.
 * Also, the session user already has full information.
 */
const getFull = procedure
  .use(authUser())
  .input(z.string())
  .output(zUser)
  .query(async ({ ctx: { me }, input: userId }) => {
    if (me.id !== userId && !isPermitted(me.roles, "UserAdmin")) {
      throw noPermissionError("用户", userId);
    }

    const u = await db.User.findByPk(userId, {
      attributes: userAttributes,
      include: userInclude,
    });

    if (!u) throw notFoundError("用户", userId);
    return u;
  });

const getUserPreference = procedure
  .use(authUser())
  .input(
    z.object({
      userId: z.string(),
    }),
  )
  .output(zUserPreference)
  .query(async ({ ctx: { me }, input: { userId } }) => {
    if (me.id !== userId && !isPermitted(me.roles, "UserAdmin")) {
      throw noPermissionError("用户", userId);
    }

    const user = await db.User.findByPk(userId, {
      attributes: ["preference"],
    });

    if (!user) throw notFoundError("用户", userId);
    return user.preference || {};
  });

const getMentorTraitsPref = procedure
  .use(authUser())
  .input(
    z.object({
      userId: z.string(),
    }),
  )
  .output(zTraitsPreference.nullable())
  .query(async ({ input: { userId } }) => {
    const user = await db.User.findByPk(userId, {
      attributes: ["preference"],
    });

    if (!user) throw notFoundError("用户", userId);
    return user.preference?.mentor?.学生特质 ?? null;
  });

/**
 * Query users using either userId or userUrl but not both
 */
const getUserProfile = procedure
  .use(authUser())
  .input(
    z.object({
      userId: z.string().optional(),
      userUrl: z.string().optional(),
    }),
  )
  .output(
    zMinUserAndProfile.merge(
      z.object({
        isMentor: z.boolean(),
        likes: z.number(),
        kudos: z.number(),
      }),
    ),
  )
  .query(async ({ ctx: { me }, input: { userId, userUrl } }) => {
    if (!!userId === !!userUrl) {
      throw generalBadRequestError(
        "Must provide either userId or userUrl and not both.",
      );
    }

    const attributes = [
      ...minUserAttributes,
      "menteeStatus",
      "roles",
      "profile",
      "likes",
      "kudos",
    ];
    const u = userId
      ? await db.User.findByPk(userId, { attributes })
      : await db.User.findOne({ where: { url: userUrl }, attributes });

    if (!u) throw notFoundError("用户", userId || userUrl || "");

    /**
     * N.B. Update /who-can-see-my-data when changing permission here.
     */

    if (
      me.id !== u.id &&
      // These roles can access profiles of all the users
      !isPermitted(me.roles, ["Mentor", "MentorshipAdmin", "UserAdmin"]) &&
      // Volunteers who are not in the roles above can only access other
      // volunteers profiles
      !(
        isPermitted(me.roles, "Volunteer") && isPermitted(u.roles, "Volunteer")
      ) &&
      // Accepted mentees can only access mentor profiles
      !(
        isAcceptedMentee(
          me.roles,
          me.menteeStatus,
          "includeTransactionalOnly",
        ) && isPermitted(u.roles, "Mentor")
      )
    ) {
      throw noPermissionError("用户", u.id);
    }

    return {
      user: u,
      profile: u.profile ?? {},
      isMentor: isPermitted(u.roles, "Mentor"),
      likes: u.likes ?? 0,
      kudos: u.kudos ?? 0,
    };
  });

const setUserProfile = procedure
  .use(authUser())
  .input(
    z.object({
      userId: z.string(),
      profile: zUserProfile,
    }),
  )
  .mutation(async ({ ctx: { me }, input: { userId, profile } }) => {
    if (me.id !== userId && !isPermitted(me.roles, "UserAdmin")) {
      throw noPermissionError("用户", userId);
    }

    const [cnt] = await db.User.update({ profile }, { where: { id: userId } });
    if (cnt == 0) throw notFoundError("用户", userId);
  });

const getUserState = procedure
  .use(authUser())
  .input(
    z
      .object({
        userId: z.string().optional(),
        returnEmptyStateIfNoPermission: z.boolean().optional(),
      })
      .optional(),
  )
  .output(zUserState)
  .query(async ({ ctx: { me }, input }) => {
    const userId = input?.userId ?? me.id;
    if (
      userId !== me.id &&
      !isPermitted(me.roles, [
        "UserAdmin",
        "MentorshipAdmin",
        "MentorshipOperator",
      ])
    ) {
      if (input?.returnEmptyStateIfNoPermission) return {};
      throw noPermissionError("用户", userId);
    }

    const u = await db.User.findByPk(userId, {
      attributes: ["state"],
    });

    if (!u) throw notFoundError("用户", userId);
    return u.state ?? {};
  });

/**
 * Fields absent from the input are not updated.
 */
const setMyState = procedure
  .use(authUser())
  .input(zUserState.partial())
  .mutation(async ({ ctx: { me }, input: state }) => {
    await sequelize.transaction(async (transaction) => {
      await setMyStateImpl(me, state, transaction);
    });
  });

export async function setMyStateImpl(
  me: User,
  state: Partial<UserState>,
  transaction: Transaction,
) {
  const u = await db.User.findByPk(me.id, {
    attributes: ["id", "state"],
    transaction,
  });
  if (!u) throw notFoundError("用户", me.id);

  // Use a whitelist approach for security: only certain fields are allowed
  // to be updated through this endpoint to ensure sensitive fields (like exam
  // completion dates) are protected and new fields are secure by default.
  const allowed: (keyof UserState)[] = [
    "consentedAt",
    "lastKudosReadAt",
    "lastTasksReadAt",
    "meetingConsentedAt",
    "declinedPearlStudentModal",
    "declinedUstcStudentModal",
    "declinedMenteeProfileModal",
  ];
  const filteredState: Partial<UserState> = {};
  for (const key of allowed) {
    if (state[key] !== undefined) {
      filteredState[key] = state[key] as any;
    }
  }

  await u.update(
    {
      state: {
        ...u.state,
        ...filteredState,
      },
    },
    { transaction },
  );
}

const setPointOfContactAndNote = procedure
  .use(authUser(["MentorshipAdmin", "MentorshipOperator"]))
  .input(
    z.object({
      userId: z.string(),
      pocId: z.string().optional(),
      pocNote: z.string().optional(),
    }),
  )
  .mutation(async ({ input: { userId, pocId, pocNote } }) => {
    if (pocId === undefined && pocNote === undefined) {
      throw generalBadRequestError("One of pocId and pocNote must be set");
    }

    const [cnt] = await db.User.update(
      {
        ...(pocId !== undefined ? { pointOfContactId: pocId } : {}),
        ...(pocNote !== undefined ? { pointOfContactNote: pocNote } : {}),
      },
      { where: { id: userId } },
    );
    if (cnt == 0) throw notFoundError("用户", userId);
    invalidateUserCache(userId);
  });

/**
 * Only MentorshipAdmin, MentorshipOperator, mentor of the applicant,
 * interviewers of the applicant, participants of the calibration (only if the
 * calibration is active), and the user themselves are allowed to call this
 * route.
 *
 * If the user is not an MentorshipAdmin, MentorshipOperator or the user being
 * requested, contact information is redacted.
 */
const getApplicant = procedure
  .use(authUser())
  .input(
    z.object({
      userId: z.string(),
      type: zInterviewType,
    }),
  )
  .output(
    z.object({
      user: zUser,
      sex: z.string().nullable(),
      application: z.record(z.string(), z.any()).nullable(),
    }),
  )
  .query(async ({ ctx: { me }, input: { userId, type } }) => {
    return await sequelize.transaction(async (transaction) => {
      const isMentee = type == "MenteeInterview";

      const user = await db.User.findByPk(userId, {
        attributes: [
          ...userAttributes,
          isMentee ? "menteeApplication" : "volunteerApplication",
          "profile",
        ],
        include: userInclude,
        transaction,
      });
      if (!user) throw notFoundError("用户", userId);

      const application = isMentee
        ? user.menteeApplication
        : user.volunteerApplication;
      const sex = user.profile?.性别 ?? null;

      const ret = {
        user,
        application,
        sex,
      };

      if (
        me.id === userId ||
        isPermitted(me.roles, ["MentorshipAdmin", "MentorshipOperator"])
      ) {
        return ret;
      }

      // Redact
      user.email = "redacted@redacted.com";
      user.wechat = "redacted";
      user.phone = "redacted";

      // Check if the user is a mentor of the mentee
      if (
        isMentee &&
        (await isPermittedtoAccessMentee(me, userId, transaction))
      ) {
        return ret;
      }

      // Check if the user is an interviewer
      const myInterviews = await db.Interview.findAll({
        where: {
          type,
          intervieweeId: userId,
        },
        attributes: [],
        include: [
          {
            model: db.InterviewFeedback,
            attributes: [],
            where: { interviewerId: me.id },
          },
        ],
        transaction,
      });
      if (myInterviews.length) return ret;

      // Check if the user is a calibration participant
      const allInterviews = await db.Interview.findAll({
        where: {
          type: type,
          intervieweeId: userId,
        },
        attributes: ["calibrationId"],
        transaction,
      });
      for (const i of allInterviews) {
        if (
          i.calibrationId &&
          (await getCalibrationAndCheckPermissionSafe(
            me,
            i.calibrationId,
            transaction,
          ))
        )
          return ret;
      }

      throw noPermissionError("申请表", user.id);
    });
  });

/**
 * TODO: Support etag. Refer to `interviewFeedbacks.update`.
 */
const setApplication = procedure
  .use(authUser("MentorshipAdmin"))
  .input(
    z.object({
      userId: z.string(),
      type: zInterviewType,
      application: z.record(z.string(), z.any()),
    }),
  )
  .mutation(async ({ input }) => {
    const [cnt] = await db.User.update(
      {
        [input.type == "MenteeInterview"
          ? "menteeApplication"
          : "volunteerApplication"]: input.application,
      },
      { where: { id: input.userId } },
    );
    if (!cnt) throw notFoundError("用户", input.userId);
  });

/**
 * List all users and their roles who have privileged user data access.
 * See RoleProfile.privilegeUserDataAccess for an explanation.
 */
const listPriviledgedUserDataAccess = procedure
  .use(authUser())
  .output(
    z.array(
      z.object({
        name: z.string().nullable(),
        roles: zRoles,
      }),
    ),
  )
  .query(async () => {
    return await db.User.findAll({
      // TODO: Optimize with postgres `?|` operator
      where: {
        [Op.or]: allRoles
          .filter((r) => roleProfile(r).privilegedUserDataAccess)
          .map((r) => ({
            roles: { [Op.contains]: [r] },
          })),
      },
      attributes: ["name", "roles"],
    });
  });

const destroy = procedure
  .use(authUser("UserAdmin"))
  .input(
    z.object({
      id: z.string(),
    }),
  )
  .mutation(async ({ input }) => {
    await sequelize.transaction(async (transaction) => {
      const user = await db.User.findByPk(input.id, { transaction });
      if (!user) throw notFoundError("用户", input.id);
      await user.destroy({ transaction });
    });
    invalidateUserCache(input.id);
  });

const getJinshujuXField = procedure
  .use(authUser())
  .input(
    z.object({
      uploadTarget: z.enum(["user", "project"]).optional(),
      projectId: z.string().optional(),
    }),
  )
  .query(async ({ input: { uploadTarget, projectId }, ctx: { me } }) => {
    const user = await db.User.findByPk(me.id, { attributes: ["url"] });
    if (!user) throw notFoundError("用户", me.id);

    const extraFields: string[] = [];
    if (uploadTarget) {
      if (uploadTarget === "project" && !projectId) {
        throw generalBadRequestError(
          "projectId is required when uploadTarget is project",
        );
      }
      extraFields.push(uploadTarget);
    }

    if (projectId) {
      extraFields.push(projectId);
    }

    return encodeXField(whiteLabel, user.url, me.id, ...extraFields);
  });

