  // This field uniquely identifies a person. See /s/why-phone.
  // It is also the key to merge accounts. See phones.ts.
  @Unique
  @Column(STRING)
  phone: string | null;

  // Must be lower case. Otherwise next-auth may not recognize the user when
  // the user uses emails in different case.
  @Unique
  @Column(STRING)
  email: string | null;

  // Used by WeChat auth. See WeChatProvider.ts and docs/WeChat.md.
  @Unique
  @Column(STRING)
  wechatUnionId: string | null;

  // Used by Yuantu SSO. See YuantuSsoProvider.ts
  @Unique
  @Column(STRING)
  ssoUserId: string | null;

