import {
  Column,
  Table,
  Model,
  PrimaryKey,
  IsUUID,
  Default,
  HasMany,
  ForeignKey,
  Unique,
  BelongsTo,
} from "sequelize-typescript";
import { CreationOptional, UUID, UUIDV4 } from "sequelize";
import ChatMessage from "./ChatMessage";
import User from "./User";

@Table
class ChatRoom extends Model {
  @IsUUID(4)
  @PrimaryKey
  @Default(UUIDV4)
  @Column(UUID)
  id: CreationOptional<string>;

  // A chat room is "owned" by a mentee user if this field is non-null.
  @Unique
  @ForeignKey(() => User)
  @Column(UUID)
  menteeId: string | null;

  /**
   * Associations
   */

  @HasMany(() => ChatMessage)
  messages: ChatMessage[];

  @BelongsTo(() => User)
  mentee: User | null;
}

export default ChatRoom;

import {
  Column,
  Table,
  Model,
  PrimaryKey,
  IsUUID,
  Default,
  ForeignKey,
  AllowNull,
  BelongsTo,
} from "sequelize-typescript";
import { CreationOptional, STRING, UUID, UUIDV4 } from "sequelize";
import User from "./User";
import ChatRoom from "./ChatRoom";

@Table({
  indexes: [
    // Used by getLastMessageCreatedAt
    { fields: ["roomId", "createdAt"] },
    // Used by getLastMessageUpdatedAt
    { fields: ["roomId", "userId", "updatedAt"] },
  ],
})
class ChatMessage extends Model {
  @IsUUID(4)
  @PrimaryKey
  @Default(UUIDV4)
  @Column(UUID)
  id: CreationOptional<string>;

  @ForeignKey(() => ChatRoom)
  @AllowNull(false)
  @Column(UUID)
  roomId: string;

  // TODO: Rename to authorId
  @ForeignKey(() => User)
  @AllowNull(false)
  @Column(UUID)
  userId: string;

  @AllowNull(false)
  @Column(STRING(1 * 1024 * 1024))
  markdown: string;

  /**
   * Associations
   */

  @BelongsTo(() => User)
  user: User;

  @BelongsTo(() => ChatRoom)
  room: ChatRoom;
}

export default ChatMessage;

import {
  Column,
  Table,
  Model,
  ForeignKey,
  BelongsTo,
} from "sequelize-typescript";
import { UUID, STRING, INTEGER } from "sequelize";
import User from "../User";
import ZodColumn from "../../modelHelpers/ZodColumn";
import { zLandmarkScore, LandmarkScore } from "../../../../shared/Map";

@Table({
  indexes: [
    {
      unique: true,
      // Composite key on userId, landmark, createdAt
      fields: ["userId", "landmark", "createdAt"],
    },
  ],
})
class LandmarkAssessment extends Model {
  @ForeignKey(() => User)
  @Column(UUID)
  userId: string;

  // If assessorId (assessor) is null, the landmark assessment is self-evaluated
  // otherwise, it is evaluated by others.
  @ForeignKey(() => User)
  @Column(UUID)
  assessorId: string | null;

  @BelongsTo(() => User, { foreignKey: "assessorId" })
  assessor: User | null;

  @Column(STRING)
  landmark: string;

  @ZodColumn(INTEGER, zLandmarkScore)
  score: LandmarkScore;

  @Column(STRING)
  markdown: string | null;
}

export default LandmarkAssessment;

import { z } from "zod";
import { zMinUser } from "./User";
import { zOptionalDateColumn } from "./DateColumn";

export const MAX_LANDMARK_SCORE = 4;

export const Longtitudes = ["情感", "智慧", "实践"] as const;

export const zLongtitude = z.enum(Longtitudes);

export const Latitudes = ["个人成长", "事业发展", "社会责任"] as const;

export const zLatitude = z.enum(Latitudes);

export type Latitude = z.TypeOf<typeof zLatitude>;

export const zLandmark = z.object({
  名称: z.string(),
  定义: z.string(),
  经度: zLongtitude,
  纬度: zLatitude,
  层级: z.array(z.string()).length(MAX_LANDMARK_SCORE),
  相关地标: z.array(z.string()).optional(),
  工具箱: z.string().optional(),
});

export type Landmark = z.TypeOf<typeof zLandmark>;

export const zLandmarkScore = z.number().int().min(1).max(MAX_LANDMARK_SCORE);

export type LandmarkScore = z.TypeOf<typeof zLandmarkScore>;

export const zLandmarkAssessment = z.object({
  createdAt: zOptionalDateColumn,
  score: zLandmarkScore,
  markdown: z.string().nullable(),
  assessor: zMinUser.nullable(),
});

export type LandmarkAssessment = z.TypeOf<typeof zLandmarkAssessment>;

