import { Sequelize } from "sequelize-typescript";
import { commonSequelizeConfig } from "./sequelizeConfig";
import { hookIsPartialAfterSequelizeInit } from "./modelHelpers/ZodColumn";
import db from "./db";

if (!process.env.DATABASE_URI) {
  throw new Error("DATABASE_URI is not set.");
}

const minPoolSize = process.env.DATABASE_MIN_POOL_SIZE
  ? parseInt(process.env.DATABASE_MIN_POOL_SIZE)
  : undefined;
const maxPoolSize = process.env.DATABASE_MAX_POOL_SIZE
  ? parseInt(process.env.DATABASE_MAX_POOL_SIZE)
  : undefined;

const sequelize = new Sequelize(process.env.DATABASE_URI, {
  ...commonSequelizeConfig(minPoolSize, maxPoolSize),
  models: Object.values(db),
});

hookIsPartialAfterSequelizeInit();

export default sequelize;

import pg from "pg";
import { SequelizeOptions } from "sequelize-typescript";

export const commonSequelizeConfig = (
  min?: number,
  max?: number,
): SequelizeOptions => {
  const options: SequelizeOptions = {
    logging: false,
    dialectModule: pg,
    retry: {
      // Error types: https://sequelize.org/api/v6/identifiers.html#errors
      match: [
        /ConnectionError/, // Fix pg vercel bug: https://github.com/orgs/vercel/discussions/234
      ],
      max: 3,
    },
  };

  if (min !== undefined || max !== undefined) {
    options.pool = {};
    if (min !== undefined) options.pool.min = min;
    if (max !== undefined) options.pool.max = max;
  }

  return options;
};
